import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, HealingResult, ProjectContext } from "../../base.ts";

/**
 * ✨ Dr. Spark — PhD in Developer Experience & UX Tooling (TypeScript)
 * Generated by Sovereign Forge.
 */
export class SparkPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "spark";
        this.name = "Spark";
        this.emoji = "✨";
        this.role = "PhD Developer Experience Engineer";
        this.phd_identity = "Developer Experience & UX Tooling (TypeScript)";
        this.stack = "TypeScript";
        this.healingPrompt = "Fix the following build system or compilation issue. Correct build configurations, tree-shaking settings, and bundler errors. Return ONLY the corrected code or a specific diff.";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        if (this.healingPrompt) {
            const { findings } = await this.auditAndHeal();
            return findings;
        }
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".tsx"],
            rules: [
          {
                    "regex": "process\\.exit\\(\\d+\\)(?![\\s\\S]{0,30}console|log|error)",
                    "issue": "Saída Silenciosa: process.exit() sem aviso ao dev. Forneça contexto visível PhD.",
                    "severity": "medium"
          },
          {
                    "regex": "throw\\s+new\\s+Error\\([\"'][\"']\\)",
                    "issue": "Erro Mudo: Error lançado com mensagem vazia PhD.",
                    "severity": "medium"
          },
          {
                    "regex": "\\.on\\([\"']error[\"']\\s*,\\s*\\(\\)\\s*=>\\s*\\{\\s*\\}\\)",
                    "issue": "Erro Invisível: Event handler de erro vazio (engolido) PhD.",
                    "severity": "high"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Spark operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Spark, PhD em Developer Experience & UX Tooling (TypeScript). Sua missão é garantir a excelência via governança PhD.`;
    }
}
